const slug = $('Storyboard Creation').item.json.book_slug;
const notesContent = $('Read Notes').item.json.content;
const templates = $('Read Templates').item.json.content || '(narrative templates not available)';
let systemPrompt = $('Read Prompt').item.json.content;

if (!notesContent) {
  throw new Error('Notes not found for book: ' + slug + '. Run research step first.');
}
if (!systemPrompt) {
  throw new Error('Storyboard prompt not found at n8n/prompts/storyboard.md');
}

// Replace placeholders
systemPrompt = systemPrompt.replace(/\{\{book_slug\}\}/g, slug);
systemPrompt = systemPrompt.replace(/\{\{notes_content\}\}/g, notesContent);
systemPrompt = systemPrompt.replace(/\{\{narrative_templates\}\}/g, templates);

// Vault context — optional, set empty if not available
systemPrompt = systemPrompt.replace(/\{\{vault_library\}\}/g, '(not available)');
systemPrompt = systemPrompt.replace(/\{\{vault_connections\}\}/g, '(not available)');
systemPrompt = systemPrompt.replace(/\{\{vault_concepts\}\}/g, '(not available)');

const userMessage = 'Create a storyboard for the book video based on the notes and chosen angle. Pick the most appropriate narrative template based on the angle and notes. Output the full storyboard document.';

return [{ json: { systemPrompt, userMessage, slug } }];

const slug = $('Build Prompt').item.json.slug;
const responseText = $json.content[0].text;

// Extract content between delimiters if present
let output;
const startMarker = '---OUTPUT START---';
const endMarker = '---OUTPUT END---';
const startIdx = responseText.indexOf(startMarker);
const endIdx = responseText.indexOf(endMarker);

if (startIdx !== -1 && endIdx !== -1) {
  output = responseText.substring(startIdx + startMarker.length, endIdx).trim();
} else {
  output = responseText.trim();
}

return [{ json: { slug, storyboardContent: output } }];

const slug = $('Extract Response').item.json.slug;
const content = $('Extract Response').item.json.storyboardContent;

// Count scenes (### Scene NN or ### ... — ...)
const sceneMatches = content.match(/^###\s+Scene\s+\d+|^###\s+.+—/gm);
const sceneCount = sceneMatches ? sceneMatches.length : 0;

// Word count
const wordCount = content.split(/\s+/).filter(w => w.length > 0).length;

const lines = [
  'Storyboard created for: ' + slug,
  '',
  'Stats:',
  '  File: books/' + slug + '/storyboard.md',
  '  Characters: ' + content.length,
  '  Words: ' + wordCount,
  '  Scenes detected: ' + sceneCount,
  '',
  'Next step: Run 04-Script workflow to generate the narration script.'
];

return [{ json: { summary: lines.join('\n') } }];
